/**
 * @name ReadTrustedStep path field flowing to checkout/FilePath operations - precise
 * @description Trace the exact flow from the user-controlled 'path' field in ReadTrustedStep to dangerous operations
 * @kind path-problem
 * @problem.severity error
 * @id java/read-trusted-step-path-injection-precise
 * @tags security
 *       external/cwe/cwe-078
 *       external/cwe/cwe-088
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module ReadTrustedPreciseConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // The 'path' field of ReadTrustedStep (set by @DataBoundConstructor)
    exists(FieldAccess fa |
      fa.getField().getDeclaringType().getName() = "ReadTrustedStep" and
      (fa.getField().hasName("path") or fa.getField().hasName("file") or fa.getField().hasName("trusted"))
    |
      source.asExpr() = fa
    )
    or
    // Constructor parameters of ReadTrustedStep
    exists(Parameter p |
      p.getCallable() instanceof Constructor and
      p.getCallable().getDeclaringType().getName() = "ReadTrustedStep"
    |
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // checkout()
    exists(MethodCall mc |
      mc.getMethod().hasName("checkout") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // FilePath.child()
    exists(MethodCall mc |
      mc.getMethod().hasName("child") and
      mc.getMethod().getDeclaringType().hasQualifiedName("hudson", "FilePath") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Any SCM fetch/read
    exists(MethodCall mc |
      (mc.getMethod().hasName("fetch") or mc.getMethod().hasName("getContents") or
       mc.getMethod().hasName("withPath") or mc.getMethod().hasName("readFile")) and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // FilePath construction
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("hudson", "FilePath") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Generic method call argument in ReadTrustedStep context  
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().getName() = "ReadTrustedStep" or
      (mc.getEnclosingCallable().getDeclaringType().getName() = "Execution" and
       mc.getEnclosingCallable().getDeclaringType().getEnclosingType().getName() = "ReadTrustedStep")
    |
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module ReadTrustedPreciseFlow = TaintTracking::Global<ReadTrustedPreciseConfig>;
import ReadTrustedPreciseFlow::PathGraph

from ReadTrustedPreciseFlow::PathNode source, ReadTrustedPreciseFlow::PathNode sink
where ReadTrustedPreciseFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "ReadTrustedStep path injection: user-controlled path from $@ reaches sensitive operation.", source.getNode(), "path input"

/**
 * @name Argument injection via scriptPath in SCMBinder to SCMFileSystem
 * @description The scriptPath in SCMBinder (set from SCM config) flows unsanitized to SCMFileSystem operations
 * @kind path-problem
 * @problem.severity error
 * @id java/scmbinder-scriptpath-injection
 * @tags security
 *       external/cwe/cwe-078
 *       external/cwe/cwe-088
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module SCMBinderConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // scriptPath field in SCMBinder
    exists(FieldAccess fa |
      fa.getField().getDeclaringType().getName() = "SCMBinder" and
      fa.getField().hasName("scriptPath")
    |
      source.asExpr() = fa
    )
    or
    // Constructor parameter for scriptPath
    exists(Parameter p |
      p.getCallable() instanceof Constructor and
      p.getCallable().getDeclaringType().getName() = "SCMBinder" and
      p.hasName("scriptPath")
    |
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // SCMFileSystem.child()
    exists(MethodCall mc |
      mc.getMethod().hasName("child") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // FilePath.child()  
    exists(MethodCall mc |
      mc.getMethod().hasName("child") and
      mc.getMethod().getDeclaringType().hasQualifiedName("hudson", "FilePath") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // checkout
    exists(MethodCall mc |
      mc.getMethod().hasName("checkout") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module SCMBinderFlow = TaintTracking::Global<SCMBinderConfig>;
import SCMBinderFlow::PathGraph

from SCMBinderFlow::PathNode source, SCMBinderFlow::PathNode sink
where SCMBinderFlow::flowPath(source, sink)
select sink.getNode(), source, sink,
  "SCMBinder: scriptPath '$@' flows unsanitized to file/SCM operation (argument injection risk).",
  source.getNode(), "scriptPath"
